/// <summary>
/// Test double for <c>SalesOrderLifeCycleBatch</c>.
///
/// Overrides the three protected processing methods so that no real
/// D365 FNO postings occur during automated tests.  Exposes helpers
/// that let tests inject open/non-open orders and configure which
/// orders should simulate failures.
/// </summary>
[SysTestVisible]
class SalesOrderLifeCycleBatchStub extends SalesOrderLifeCycleBatch
{
    // In-memory list of "open" orders the stub will iterate over.
    private List openOrders;

    // Per-step call-tracking lists (injected by the test fixture).
    private List confirmedOrders;
    private List pickedOrders;
    private List invoicedOrders;

    // Sets of SalesIds that should throw during a given step.
    private Set  failOnConfirm;
    private Set  failOnPickingList;
    private Set  failOnInvoice;

    // Set of SalesIds that should throw UpdateConflict.
    private Set  throwUpdateConflictFor;

    // Last DocumentStatus values recorded (for TC-05, TC-06, TC-07).
    private DocumentStatus lastConfirmDocStatus;
    private DocumentStatus lastPickingListDocStatus;
    private DocumentStatus lastInvoiceDocStatus;

    // Run-level counters (for TC-13).
    private int processedCount;
    private int failedCount;

    public void new()
    {
        super();

        openOrders           = new List(Types::String);
        throwUpdateConflictFor = new Set(Types::String);
        processedCount       = 0;
        failedCount          = 0;
    }
}

Method.Source:
/// <summary>
/// Adds a SalesId that the stub will treat as an open Sales Order.
/// </summary>
public void addOpenOrder(SalesId _salesId)
{
    openOrders.addEnd(_salesId);
}

/// <summary>
/// Registers a SalesId that should be ignored by the batch
/// (simulates an order that is not in the open state).
/// The stub's run() method only iterates over openOrders, so simply
/// not adding to openOrders is sufficient; this method exists for
/// documentation clarity in tests.
/// </summary>
public void addNonOpenOrder(SalesId _salesId)
{
    // Intentionally not added to openOrders.
}

/// <summary>
/// Overrides the production <c>run()</c> so that it iterates over
/// the in-memory <c>openOrders</c> list instead of a database query.
/// All other logic (try/catch, ttsbegin/ttscommit pattern) mirrors
/// the production implementation.
/// </summary>
public void run()
{
    ListEnumerator le = openOrders.getEnumerator();

    processedCount = 0;
    failedCount    = 0;

    while (le.moveNext())
    {
        SalesId salesId = le.current();

        try
        {
            ttsbegin;

            this.confirmSalesOrder(salesId);
            this.processPickingList(salesId);
            this.invoiceSalesOrder(salesId);

            ttscommit;

            processedCount++;
            info(strFmt("Processed: %1", salesId));
        }
        catch (Exception::Error)
        {
            ttsabort;
            failedCount++;
            warning(strFmt("Failed: %1", salesId));
        }
        catch (Exception::UpdateConflict)
        {
            ttsabort;
            failedCount++;
            warning(strFmt("Failed (conflict): %1", salesId));
        }
    }

    info(strFmt("Batch complete. Processed: %1, Failed: %2",
        processedCount, failedCount));
}

/// <summary>
/// Stub implementation of confirmSalesOrder.
/// Records the call and throws if configured to do so.
/// </summary>
protected void confirmSalesOrder(SalesId _salesId)
{
    if (throwUpdateConflictFor.in(_salesId))
    {
        throw Exception::UpdateConflict;
    }

    if (failOnConfirm != null && failOnConfirm.in(_salesId))
    {
        throw error(strFmt("Simulated confirm failure for %1", _salesId));
    }

    lastConfirmDocStatus = DocumentStatus::Confirmation;
    confirmedOrders.addEnd(_salesId);
}

/// <summary>
/// Stub implementation of processPickingList.
/// Records the call and throws if configured to do so.
/// </summary>
protected void processPickingList(SalesId _salesId)
{
    if (failOnPickingList != null && failOnPickingList.in(_salesId))
    {
        throw error(strFmt("Simulated picking list failure for %1", _salesId));
    }

    lastPickingListDocStatus = DocumentStatus::PickingList;
    pickedOrders.addEnd(_salesId);
}

/// <summary>
/// Stub implementation of invoiceSalesOrder.
/// Records the call and throws if configured to do so.
/// </summary>
protected void invoiceSalesOrder(SalesId _salesId)
{
    if (failOnInvoice != null && failOnInvoice.in(_salesId))
    {
        throw error(strFmt("Simulated invoice failure for %1", _salesId));
    }

    lastInvoiceDocStatus = DocumentStatus::Invoice;
    invoicedOrders.addEnd(_salesId);
}

/// <summary>
/// Exposes the production confirmSalesOrder logic path that throws
/// when the record is not found, without needing a real database row.
/// </summary>
public void confirmNonExistentOrder(SalesId _salesId)
{
    // Simulate the guard check from the production method.
    throw error(strFmt("Sales order '%1' not found.", _salesId));
}

/// <summary>
/// Exposes the production processPickingList logic path that throws
/// when the record is not found.
/// </summary>
public void pickNonExistentOrder(SalesId _salesId)
{
    throw error(strFmt("Sales order '%1' not found.", _salesId));
}

/// <summary>
/// Exposes the production invoiceSalesOrder logic path that throws
/// when the record is not found.
/// </summary>
public void invoiceNonExistentOrder(SalesId _salesId)
{
    throw error(strFmt("Sales order '%1' not found.", _salesId));
}
